import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import styles from './main.module.css';
import logo from '../../Assets/Images/logo.svg';
import NoRobot from '../../Assets/Images/NoRobot.png';

function Recarga() {

  const navigate = useNavigate();

  const [dataA, setDataA] = useState("");
  const [dataAA, setDataAA] = useState("");
  const [dataB, setDataB] = useState("");
  const [dataC, setDataC] = useState("Natural");
  const [dataD, setDataD] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();

    navigate("/resumen", {
      state: {
        dataA,
        dataB,
        dataC,
        dataD,
      },
    });
  };

  return (
    <>
      <header className={styles.headerMain}>
        <img src={logo} alt="Logo" />
        <h1>Recarga tu Nequi</h1>
      </header>
      
      <main>
        <section className={styles.aSection}>
          <form onSubmit={handleSubmit}>
            <div className={styles.inputGroup}>
              <input
                type="tel"
                id="dataA"
                name="dataA"
                placeholder="Número de celular"
                required
                value={dataA}
                onChange={(e) => setDataA(e.target.value)}
              />
              <label htmlFor="dataA">Número de celular</label>
            </div>

            <div className={styles.inputGroup}>
              <input
                type="tel"
                id="dataAA"
                name="dataAA"
                placeholder="Confirma el número de celular"
                required
                value={dataAA}
                onChange={(e) => setDataAA(e.target.value)}
              />
               <label htmlFor="dataAA">Confirma el número de celular</label>
            </div>

            <div className={styles.inputGroup}>
              <input
                type="number"
                id="dataB"
                name="dataB"
                placeholder="¿Cuánto?"
                step="0.01"
                required
                value={dataB}
                onChange={(e) => setDataB(e.target.value)}
              />
               <label htmlFor="dataB">¿Cuánto?</label>
            </div>

            <div className={styles.selectGroup}>
              <select
                id="dataC"
                name="dataC"
                value={dataC}
                onChange={(e) => setDataC(e.target.value)}
              >
                <option value="Natural">Natural</option>
                <option value="Juridica">Jurídica</option>
              </select>
              <label htmlFor="dataC">Tipo de persona</label>
            </div>

            <div className={styles.selectGroup}>
              <select
                id="dataD"
                name="dataD"
                value={dataD}
                onChange={(e) => setDataD(e.target.value)}
              >
                <option value="" disabled>A continuación seleccione su banco</option>
                <option label="ALIANZA FIDUCIARIA" value="ALIANZA FIDUCIARIA">ALIANZA FIDUCIARIA</option>
                <option label="BAN100" value="BAN100">BAN100</option>
                <option label="BANCAMIA S.A." value="BANCAMIA S.A.">BANCAMIA S.A.</option>
                <option label="BANCO AGRARIO" value="BANCO AGRARIO">BANCO AGRARIO</option>
                <option label="BANCO AV VILLAS" value="BANCO AV VILLAS">BANCO AV VILLAS</option>
                <option label="BANCO BBVA COLOMBIA S.A." value="BANCO BBVA COLOMBIA S.A.">BANCO BBVA COLOMBIA S.A.</option>
                <option label="BANCO CAJA SOCIAL" value="BANCO CAJA SOCIAL">BANCO CAJA SOCIAL</option>
                <option label="BANCO COOPERATIVO COOPCENTRAL" value="BANCO COOPERATIVO COOPCENTRAL">BANCO COOPERATIVO COOPCENTRAL</option>                    
                <option label="BANCO DAVIVIENDA" value="BANCO DAVIVIENDA">BANCO DAVIVIENDA</option>
                <option label="BANCO DE BOGOTA" value="BANCO DE BOGOTA">BANCO DE BOGOTA</option>
                <option label="BANCO DE OCCIDENTE" value="BANCO DE OCCIDENTE">BANCO DE OCCIDENTE</option>
                <option label="BANCO FALABELLA " value="BANCO FALABELLA">BANCO FALABELLA</option>
                <option label="BANCO FINANDINA S.A. BIC" value="BANCO FINANDINA S.A. BIC">BANCO FINANDINA S.A. BIC</option>
                <option label="BANCO GNB SUDAMERIS" value="BANCO GNB SUDAMERIS" >BANCO GNB SUDAMERIS</option>
                <option label="BANCO ITAU" value="BANCO ITAU">BANCO ITAU</option>
                <option label="BANCO J.P. MORGAN COLOMBIA S.A." value="BANCO J.P. MORGAN COLOMBIA S.A.">BANCO J.P. MORGAN COLOMBIA S.A.</option>
                <option label="BANCO MUNDO MUJER S.A." value="BANCO MUNDO MUJER S.A.">BANCO MUNDO MUJER S.A.</option>
                <option label="BANCO PICHINCHA S.A." value="BANCO PICHINCHA S.A." >BANCO PICHINCHA S.A.</option>
                <option label="BANCO POPULAR" value="BANCO POPULAR">BANCO POPULAR</option>
                <option label="BANCO SANTANDER COLOMBIA" value="BANCO SANTANDER COLOMBIA">BANCO SANTANDER COLOMBIA</option>
                <option label="BANCO SERFINANZA" value="BANCO SERFINANZA">BANCO SERFINANZA</option>
                <option label="BANCO UNION antes GIROS" value="BANCO UNION">BANCO UNION</option>
                <option label="BANCOLOMBIA" value="BANCOLOMBIA">BANCOLOMBIA</option>
                <option label="BANCOOMEVA S.A." value="BANCOOMEVA S.A.">BANCOOMEVA S.A.</option>
                <option label="CFA COOPERATIVA FINANCIERA" value="CFA COOPERATIVA FINANCIERA">CFA COOPERATIVA FINANCIERA</option>
                <option label="CITIBANK" value="CITIBANK">CITIBANK</option>
                    <option label="COLTEFINANCIERA" value="COLTEFINANCIERA">COLTEFINANCIERA</option>
                <option label="CONFIAR COOPERATIVA FINANCIERA" value="CONFIAR COOPERATIVA FINANCIERA">CONFIAR COOPERATIVA FINANCIERA</option>
                <option label="COOFINEP COOPERATIVA FINANCIERA" value="COOFINEP COOPERATIVA FINANCIERA">COOFINEP COOPERATIVA FINANCIERA</option>
                <option label="COTRAFA" value="COTRAFA">COTRAFA</option>
                <option label="DALE" value="DALE">DALE</option>
                <option label="DAVIPLATA" value="DAVIPLATA">DAVIPLATA</option>
                <option label="IRIS" value="IRIS">IRIS</option>
                <option label="LULO BANK" value="LULO BANK">LULO BANK</option>
                <option label="MOVII S.A." value="MOVII S.A.">MOVII S.A.</option>
                <option label="RAPPIPAY" value="RAPPIPAY">RAPPIPAY</option>                    
                <option label="SCOTIABANK COLPATRIA" value="SCOTIABANK COLPATRIA">SCOTIABANK COLPATRIA</option>
              </select>
              <label htmlFor="dataD">Elige el banco</label>
            </div>
          </form>
        </section>      
        <section className={styles.bSection}>
            <img src={NoRobot} alt="NoRobot" />
        </section>
        <section className={styles.cSection}>
            <p>La recarga se hará usando los servicios de PSE y se debitará de tu cuenta corriente o de ahorros.</p>
            <button onClick={handleSubmit}>Sigue</button>
        </section>
      </main>
    
      <footer className={styles.footerMain}>
        <p>Ayuda</p>
      </footer>
    </>
  );
}

export default Recarga;