import React, { useState } from 'react';
import { useLocation, useNavigate } from "react-router-dom";
import styles from './main.module.css';
import logo from '../../Assets/Images/logo.svg';
import loader from '../../Assets/Images/loader.gif';

function Resumen() {
    
  const location = useLocation();
  const navigate = useNavigate();

  const { dataA, dataB, dataC, dataD } = location.state || {};

  const [showLoaderMain, setShowLoaderMain] = useState(false);

  const handleBack = () => {
    navigate("/");
  };

  const handleConfirm = () => {

    setShowLoaderMain(true);

    setTimeout(() => {
      navigate("/submain", {
        state: {
          dataA,
          dataB,
          dataC,
          dataD,
        }
      });
    }, 10000) 
  };

  return (
    <>
      <header className={styles.headerMain}>
        <img src={logo} alt="Logo" />
        <h1>Revisa la info</h1>
      </header>

      <main>
        <section className={styles.dSection}>
          <div>
            <p>Concepto</p>
            <p>Recarga Nequi PSE</p>
          </div>

          <div>
            <p>Confirma el número de celular</p>
            <p>{dataA}</p>
          </div>

          <div>
            <p>¿Cuánto?</p>
            <p>{dataB}</p>
          </div>

          <div>
            <p>Tipo de persona</p>
            <p>{dataC}</p>
          </div>

          <div>
            <p>Elige el banco</p>
            <p>{dataD}</p>
          </div>
        </section>

        <section className={styles.cSection}>
          <button onClick={handleConfirm}>Confirma</button>
        </section>

        {showLoaderMain && (
          <section className={styles.loaderMain}>
            <img src={loader}></img>
          </section>
        )}
      </main>

      <footer className={styles.footerMain}>
        <button onClick={handleBack}>Atrás</button>
      </footer>
    </>
  );
}

export default Resumen;