import React from "react";
import { useNavigate } from "react-router-dom";
import styles from './main.module.css';
import logoResumenPago from '../../Assets/Images/logoResumenPago.svg';
import x from '../../Assets/Images/x.png';

function ResumenPago() {

  const navigate = useNavigate();

  const handleConfirm = () => {
    navigate("/")
  };

  return (
    <>
      <main className={styles.mainResumenPago}>
        <img src={logoResumenPago} alt="Logo Resumen Pago"></img>
        <h1>¡Recarga rechazada!</h1>
        <div>
            <img src={x} alt="Transacción Rechazada"></img>
            <p>¡Rechazado!</p>
        </div>
        <p>Tu recarga fue rechazada. Revisa tu saldo en el Disponible en la app Nequi.</p>
        <button onClick={handleConfirm}>Intentar nuevamente</button>
      </main>
    </>
  );
}

export default ResumenPago;